var e=[{id:`L6_1`,type:`dialog`,speaker:`ANDY_ATELIER_NULL_NULL`,text:{KOREA:`벌써 침식체가 몰려들고 있네.`,JPN:`もう侵食体が押し寄せて来てる。`,ENG:`C.O.s are already swarming in.`,TWN:`侵蝕體都往這裡來了。`},stage:{bg:`COUNTERSIDE_WELL`,bgm:`CUTSCENE_AMBIENT_RAIN`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`ANDY_ATELIER_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`SEOSAENG_ATELIER_NULL_BLADE`,text:{KOREA:`연료로 쓰인 이터니움에 이끌렸겠지.`,JPN:`燃料にしているエタニウムに引きつけられたか。`,ENG:`Drawn to the Eternium we used as fuel.`,TWN:`是被當作燃料的永恆之金吸引過來的。`},stage:{bg:`COUNTERSIDE_WELL`,bgm:`CUTSCENE_AMBIENT_RAIN`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`ANDY_ATELIER_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`SEOSAENG_ATELIER_NULL_BLADE`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`SEOSAENG_ATELIER_NULL_BLADE`,text:{KOREA:`<color=#ffd34c>과.위.장</color>이 와류흔으로 모이는 힘을 충분히 수집할 동안 지켜야 하네.`,JPN:`<color=#ffd34c>過向装</color>が渦流痕に集まる力を十分に溜めるまで守らねばならん。`,ENG:`We need to hold them off until the <color=#ffd34c>DTP</color> finishes gathering power from the Vortex Scar.`,TWN:`我們要撐到讓<color=#ffd34c>回裝置</color>收集到足夠的渦流痕力量為止。`},stage:{bg:`COUNTERSIDE_WELL`,bgm:`CUTSCENE_AMBIENT_RAIN`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`ANDY_ATELIER_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`SEOSAENG_ATELIER_NULL_BLADE`,face:`UNIT_SERIOUS`}}}},{id:`L11_1`,type:`dialog`,speaker:`ANDY_ATELIER_NULL_NULL`,text:{KOREA:`앗, 큰 건 징그러워서 질색인데.`,JPN:`あっ、大きいのは気持ち悪いからやだ。`,ENG:`Ugh, I hate the big ones. They creep me out.`,TWN:`噁，大塊頭的好噁，超討厭。`},stage:{bg:`COUNTERSIDE_WELL`,bgm:`BATTLE_NORMAL_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`ANDY_ATELIER_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`SEOSAENG_ATELIER_NULL_BLADE`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`ANDY_ATELIER_NULL_NULL`,text:{KOREA:`내가 작은 녀석들 처리할게. 사부가 큰 거 잡아줄 거지?`,JPN:`私が小さいほうをやっつけるから、大きいのは師匠が相手してよ。`,ENG:`I'll handle the little guys. Master, you take the big one.`,TWN:`我去對付小隻的。師父你對付大隻的。`},stage:{bg:`COUNTERSIDE_WELL`,bgm:`BATTLE_NORMAL_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`ANDY_ATELIER_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`SEOSAENG_ATELIER_NULL_BLADE`,face:`UNIT_IDLE`}}}},{id:`L13_1`,type:`dialog`,speaker:`SEOSAENG_ATELIER_NULL_BLADE`,text:{KOREA:`그렇게 하지.`,JPN:`そうしよう。`,ENG:`Very well.`,TWN:`好。`},stage:{bg:`COUNTERSIDE_WELL`,bgm:`BATTLE_NORMAL_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`ANDY_ATELIER_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`SEOSAENG_ATELIER_NULL_BLADE`,face:`UNIT_DESPAIR`}}}},{id:`L15_1`,type:`dialog`,speaker:`SEOSAENG_ATELIER_NULL_BLADE`,text:{KOREA:`늘 하는 얘기지만, 조심하게.`,JPN:`いつも言っていることだが、気をつけるのだぞ。`,ENG:`As I always say, stay sharp.`,TWN:`老話一句，小心。`},stage:{bg:`COUNTERSIDE_WELL`,bgm:`BATTLE_NORMAL_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOSAENG_ATELIER_NULL_BLADE`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`ANDY_ATELIER_NULL_NULL`,text:{KOREA:`걱정 마!`,JPN:`大丈夫だって！`,ENG:`Don't worry!`,TWN:`別擔心！`},stage:{bg:`COUNTERSIDE_WELL`,bgm:`BATTLE_NORMAL_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANDY_ATELIER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};